import { useState, useRef, useEffect } from "react";
import axios from "axios";

const API = "http://localhost:5000/api";

const CUISINES = ["Any", "South Indian", "North Indian", "Chinese", "Italian", "Continental"];
const MOODS = [
  { emoji: "😊", label: "Happy" },
  { emoji: "😢", label: "Sad" },
  { emoji: "😤", label: "Stressed" },
  { emoji: "😴", label: "Tired" },
  { emoji: "🤒", label: "Sick" },
  { emoji: "💪", label: "Energetic" },
];
const DIET_TYPES = [
  { emoji: "🌿", label: "Any" },
  { emoji: "🥗", label: "Veg" },
  { emoji: "🍖", label: "Non-Veg" },
  { emoji: "🌱", label: "Vegan" },
];
const QUICK_PROMPTS = [
  { emoji: "🍅", text: "I have tomato, onion and rice" },
  { emoji: "🌶️", text: "Something spicy for dinner" },
  { emoji: "🌅", text: "Light breakfast ideas" },
  { emoji: "🥘", text: "I want comfort food" },
  { emoji: "⚡", text: "Quick 15 min recipe" },
  { emoji: "🏃", text: "Post workout meal" },
];

const getMealTime = () => {
  const hour = new Date().getHours();
  if (hour >= 5 && hour < 11) return { label: "Breakfast", emoji: "🌅" };
  if (hour >= 11 && hour < 16) return { label: "Lunch", emoji: "☀️" };
  if (hour >= 16 && hour < 19) return { label: "Snacks", emoji: "🍎" };
  return { label: "Dinner", emoji: "🌙" };
};

const StatCard = ({ label, value, color, emoji, bg }) => (
  <div style={{
    background: bg,
    borderRadius: "16px",
    padding: "20px",
    display: "flex",
    alignItems: "center",
    gap: "16px",
    border: `1px solid ${color}22`,
    transition: "transform 0.2s",
    cursor: "default",
  }}
    onMouseEnter={e => e.currentTarget.style.transform = "translateY(-2px)"}
    onMouseLeave={e => e.currentTarget.style.transform = "translateY(0)"}
  >
    <div style={{
      width: "48px", height: "48px",
      background: `${color}22`,
      borderRadius: "12px",
      display: "flex", alignItems: "center", justifyContent: "center",
      fontSize: "22px", flexShrink: 0
    }}>{emoji}</div>
    <div>
      <p style={{ margin: 0, fontSize: "12px", color: "#888", fontWeight: "500" }}>{label}</p>
      <p style={{ margin: "3px 0 0", fontSize: "20px", fontWeight: "700", color }}>{value}</p>
    </div>
  </div>
);

export default function App() {
  const [page, setPage] = useState("login");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [token, setToken] = useState("");
  const [userName, setUserName] = useState("");
  const [query, setQuery] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [authMessage, setAuthMessage] = useState("");
  const [theme, setTheme] = useState("dark");
  const [cuisine, setCuisine] = useState("Any");
  const [favourites, setFavourites] = useState([]);
  const [mood, setMood] = useState("");
  const [dietType, setDietType] = useState("Any");
  const [bmi, setBmi] = useState(null);
  const [height, setHeight] = useState("");
  const [weight, setWeight] = useState("");
  const [waterCount, setWaterCount] = useState(0);
  const [calorieLog, setCalorieLog] = useState([]);
  const [calorieInput, setCalorieInput] = useState("");
  const [mealPlan, setMealPlan] = useState("");
  const [mealPlanLoading, setMealPlanLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const chatEndRef = useRef(null);
  const mealTime = getMealTime();

  const isDark = theme === "dark";
  const C = {
    bg: isDark ? "#0a0a14" : "#f5f7ff",
    sidebar: isDark ? "#0f1023" : "#ffffff",
    surface: isDark ? "#141428" : "#ffffff",
    card: isDark ? "#181830" : "#f8f9ff",
    hover: isDark ? "#1e1e3a" : "#f0f2ff",
    bubble_ai: isDark ? "#1a2744" : "#eef2ff",
    bubble_user: isDark ? "#1a3a2a" : "#e8f5e9",
    text: isDark ? "#e8e8f0" : "#1a1a2e",
    subtext: isDark ? "#6b6b8a" : "#6b7280",
    border: isDark ? "#1e1e35" : "#e5e7eb",
    accent: "#ff6b35",
    blue: "#4361ee",
    teal: "#4cc9f0",
    green: "#06d6a0",
    purple: "#7c3aed",
    pink: "#f72585",
    yellow: "#ffd60a",
  };

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const logout = () => { setToken(""); setPage("login"); setMessages([]); };

  const register = async () => {
    try {
      const res = await axios.post(`${API}/auth/register`, { name, email, password });
      setAuthMessage(res.data.message);
      setPage("login");
    } catch (err) { setAuthMessage(err.response?.data?.message || "Error"); }
  };

  const login = async () => {
    try {
      const res = await axios.post(`${API}/auth/login`, { email, password });
      setToken(res.data.token);
      setUserName(res.data.user.name);
      setMessages([{
        role: "ai",
        text: `Hey ${res.data.user.name}! 👋 I'm NutriAI, your personal AI chef. It's ${mealTime.emoji} ${mealTime.label} time — what are you craving today?`,
        time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })
      }]);
      setPage("home");
    } catch (err) { setAuthMessage(err.response?.data?.message || "Error"); }
  };

  const getSuggestion = async (customQuery) => {
    const q = customQuery || query;
    if (!q.trim()) return;
    const contextPrompt = `User query: ${q}
Current meal time: ${mealTime.label}
Cuisine: ${cuisine !== "Any" ? cuisine : "Any"}
Diet: ${dietType !== "Any" ? dietType : "No restriction"}
Mood: ${mood || "Not specified"}
Suggest a perfect Indian dish. Include: dish name, why it fits, 5-6 ingredients, 3-4 prep steps, nutrition (calories/protein/carbs/fat), and one health tip. Be friendly and concise!`;

    setMessages(prev => [...prev,
    { role: "user", text: `${mood ? mood + " · " : ""}${dietType !== "Any" ? dietType + " · " : ""}${q}`, time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) },
    { role: "ai", text: "typing", time: "" }
    ]);
    setQuery("");
    setLoading(true);
    try {
      const res = await axios.post(`${API}/suggest`, { query: contextPrompt }, { headers: { Authorization: `Bearer ${token}` } });
      setMessages(prev => [...prev.filter(m => m.text !== "typing"), { role: "ai", text: res.data.suggestion, time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) }]);
    } catch {
      setMessages(prev => [...prev.filter(m => m.text !== "typing"), { role: "ai", text: "Oops! Something went wrong. Try again! 😅", time: "" }]);
    }
    setLoading(false);
  };

  const generateMealPlan = async () => {
    setMealPlanLoading(true); setMealPlan("");
    try {
      const res = await axios.post(`${API}/suggest`,
        { query: `Create a healthy Indian meal plan for one day. Diet: ${dietType !== "Any" ? dietType : "No restriction"}. Cuisine: ${cuisine}. BMI: ${bmi || "unknown"}. Mood: ${mood || "normal"}. Format: 🌅 Breakfast (7AM) · 🍎 Snack (10:30AM) · 🍽️ Lunch (1PM) · ☕ Snack (4:30PM) · 🌙 Dinner (8PM). Include calories per meal and total. Make it practical!` },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setMealPlan(res.data.suggestion);
    } catch { setMealPlan("Error generating meal plan. Please try again!"); }
    setMealPlanLoading(false);
  };

  const input = (placeholder, value, onChange, type = "text", mb = "14px") => (
    <input
      type={type}
      placeholder={placeholder}
      value={value}
      onChange={onChange}
      style={{
        width: "100%", padding: "13px 16px", marginBottom: mb,
        borderRadius: "12px", border: `1.5px solid ${C.border}`,
        background: C.card, color: C.text, fontSize: "14px",
        outline: "none", boxSizing: "border-box", transition: "border 0.2s",
      }}
      onFocus={e => e.target.style.borderColor = C.accent}
      onBlur={e => e.target.style.borderColor = C.border}
    />
  );

  const btn = (label, onClick, style = {}) => (
    <button onClick={onClick} style={{
      padding: "13px 24px", background: `linear-gradient(135deg, ${C.accent}, #ff8c42)`,
      color: "white", border: "none", borderRadius: "12px", cursor: "pointer",
      fontSize: "14px", fontWeight: "600", transition: "opacity 0.2s, transform 0.1s", ...style
    }}
      onMouseEnter={e => { e.target.style.opacity = "0.9"; e.target.style.transform = "translateY(-1px)"; }}
      onMouseLeave={e => { e.target.style.opacity = "1"; e.target.style.transform = "translateY(0)"; }}
    >{label}</button>
  );

  // AUTH PAGES
  if (page === "login" || page === "register") {
    return (
      <div style={{
        minHeight: "100vh", background: `linear-gradient(135deg, #0a0a14 0%, #141428 50%, #0f1023 100%)`,
        display: "flex", alignItems: "center", justifyContent: "center",
        fontFamily: "'Segoe UI', sans-serif",
      }}>
        {/* Animated background orbs */}
        <div style={{ position: "fixed", top: "10%", left: "10%", width: "300px", height: "300px", background: `${C.accent}15`, borderRadius: "50%", filter: "blur(60px)", pointerEvents: "none" }} />
        <div style={{ position: "fixed", bottom: "10%", right: "10%", width: "250px", height: "250px", background: `${C.blue}15`, borderRadius: "50%", filter: "blur(60px)", pointerEvents: "none" }} />

        <div style={{
          background: "rgba(20,20,40,0.8)", backdropFilter: "blur(20px)",
          borderRadius: "24px", padding: "48px 40px", width: "100%", maxWidth: "420px",
          border: "1px solid rgba(255,255,255,0.08)", boxShadow: "0 30px 80px rgba(0,0,0,0.5)",
        }}>
          {/* Logo */}
          <div style={{ textAlign: "center", marginBottom: "36px" }}>
            <div style={{
              width: "72px", height: "72px", background: `linear-gradient(135deg, ${C.accent}, #ff8c42)`,
              borderRadius: "20px", display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: "36px", margin: "0 auto 16px", boxShadow: `0 8px 30px ${C.accent}40`
            }}>🍱</div>
            <h1 style={{ margin: "0 0 6px", color: "#fff", fontSize: "28px", fontWeight: "700" }}>NutriAI</h1>
            <p style={{ margin: 0, color: "#6b6b8a", fontSize: "14px" }}>Your Personal Indian Chef Assistant</p>
          </div>

          {/* Tabs */}
          <div style={{ display: "flex", background: "rgba(255,255,255,0.05)", borderRadius: "12px", padding: "4px", marginBottom: "28px" }}>
            {["login", "register"].map(tab => (
              <button key={tab} onClick={() => setPage(tab)} style={{
                flex: 1, padding: "10px", background: page === tab ? `linear-gradient(135deg, ${C.accent}, #ff8c42)` : "transparent",
                color: page === tab ? "white" : "#6b6b8a", border: "none", borderRadius: "10px",
                cursor: "pointer", fontSize: "14px", fontWeight: "600", transition: "all 0.2s", textTransform: "capitalize"
              }}>{tab}</button>
            ))}
          </div>

          {authMessage && (
            <div style={{ background: "rgba(255,107,53,0.15)", border: "1px solid rgba(255,107,53,0.3)", borderRadius: "10px", padding: "10px 14px", marginBottom: "16px", color: C.accent, fontSize: "13px" }}>
              {authMessage}
            </div>
          )}

          {page === "register" && input("Full Name", name, e => setName(e.target.value))}
          {input("Email address", email, e => setEmail(e.target.value), "email")}
          {input("Password", password, e => setPassword(e.target.value), "password")}

          <button
            onClick={page === "login" ? login : register}
            style={{
              width: "100%", padding: "14px", background: `linear-gradient(135deg, ${C.accent}, #ff8c42)`,
              color: "white", border: "none", borderRadius: "12px", cursor: "pointer",
              fontSize: "15px", fontWeight: "700", boxShadow: `0 6px 20px ${C.accent}40`,
              transition: "transform 0.1s"
            }}
            onMouseEnter={e => e.target.style.transform = "translateY(-1px)"}
            onMouseLeave={e => e.target.style.transform = "translateY(0)"}
          >
            {page === "login" ? "Sign In →" : "Create Account →"}
          </button>
        </div>
      </div>
    );
  }

  // SIDEBAR
  const Sidebar = () => (
    <div style={{
      width: sidebarOpen ? "250px" : "0px",
      minWidth: sidebarOpen ? "250px" : "0px",
      background: C.sidebar,
      borderRight: `1px solid ${C.border}`,
      display: "flex", flexDirection: "column",
      overflow: "hidden",
      transition: "all 0.3s ease",
      fontFamily: "'Segoe UI', sans-serif",
    }}>
      <div style={{ padding: "20px 16px", overflowY: "auto", flex: 1, display: "flex", flexDirection: "column" }}>

        {/* Logo */}
        <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "24px", paddingBottom: "20px", borderBottom: `1px solid ${C.border}` }}>
          <div style={{ width: "36px", height: "36px", background: `linear-gradient(135deg, ${C.accent}, #ff8c42)`, borderRadius: "10px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "18px", flexShrink: 0 }}>🍱</div>
          <div>
            <p style={{ margin: 0, fontWeight: "700", fontSize: "15px", color: C.accent }}>NutriAI</p>
            <p style={{ margin: 0, fontSize: "10px", color: C.subtext }}>Personal Chef Assistant</p>
          </div>
        </div>

        {/* User */}
        <div style={{ background: C.card, borderRadius: "12px", padding: "12px 14px", marginBottom: "20px", border: `1px solid ${C.border}` }}>
          <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
            <div style={{ width: "36px", height: "36px", background: `linear-gradient(135deg, ${C.blue}, ${C.purple})`, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "16px" }}>
              {userName.charAt(0).toUpperCase()}
            </div>
            <div>
              <p style={{ margin: 0, fontWeight: "600", fontSize: "13px" }}>{userName}</p>
              <p style={{ margin: 0, fontSize: "11px", color: C.accent }}>{mealTime.emoji} {mealTime.label} time</p>
            </div>
          </div>
        </div>

        {/* Nav */}
        <div style={{ marginBottom: "20px" }}>
          <p style={{ fontSize: "10px", color: C.subtext, marginBottom: "8px", textTransform: "uppercase", letterSpacing: "1.5px", fontWeight: "600" }}>Menu</p>
          {[
            { id: "home", emoji: "💬", label: "AI Chat" },
            { id: "dashboard", emoji: "📊", label: "Dashboard" },
            { id: "mealplan", emoji: "🗓️", label: "Meal Planner" },
          ].map(nav => (
            <button key={nav.id} onClick={() => setPage(nav.id)} style={{
              display: "flex", alignItems: "center", gap: "10px",
              width: "100%", padding: "10px 12px", marginBottom: "4px",
              background: page === nav.id ? `${C.accent}15` : "transparent",
              color: page === nav.id ? C.accent : C.text,
              border: page === nav.id ? `1px solid ${C.accent}30` : "1px solid transparent",
              borderRadius: "10px", cursor: "pointer", fontSize: "13px", fontWeight: page === nav.id ? "600" : "400",
              textAlign: "left", transition: "all 0.2s"
            }}>
              <span>{nav.emoji}</span> {nav.label}
            </button>
          ))}
        </div>

        {/* Mood */}
        <div style={{ marginBottom: "16px" }}>
          <p style={{ fontSize: "10px", color: C.subtext, marginBottom: "8px", textTransform: "uppercase", letterSpacing: "1.5px", fontWeight: "600" }}>Your Mood</p>
          <div style={{ display: "flex", flexWrap: "wrap", gap: "5px" }}>
            {MOODS.map(m => (
              <button key={m.label} onClick={() => setMood(mood === m.label ? "" : m.label)} style={{
                padding: "5px 9px", fontSize: "11px", border: "none", borderRadius: "8px", cursor: "pointer",
                background: mood === m.label ? C.accent : C.card,
                color: mood === m.label ? "white" : C.subtext,
                transition: "all 0.2s"
              }}>{m.emoji} {m.label}</button>
            ))}
          </div>
        </div>

        {/* Diet */}
        <div style={{ marginBottom: "16px" }}>
