    }}>
      <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
        <button onClick={() => setSidebarOpen(!sidebarOpen)} style={{
          background: C.card, border: `1px solid ${C.border}`, color: C.text,
          borderRadius: "8px", padding: "6px 10px", cursor: "pointer", fontSize: "14px"
        }}>☰</button>
        <div>
          <p style={{ margin: 0, fontWeight: "600", fontSize: "15px" }}>{title}</p>
          {subtitle && <p style={{ margin: 0, fontSize: "11px", color: C.green }}>● {subtitle}</p>}
        </div>
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: "8px", fontSize: "12px", color: C.subtext }}>
        <span>{mealTime.emoji} {mealTime.label}</span>
        <span>•</span>
        <span>{messages.filter(m => m.role === "user").length} queries</span>
      </div>
    </div>
  );

  // DASHBOARD
  if (page === "dashboard") return (
    <div style={{ display: "flex", height: "100vh", fontFamily: "'Segoe UI', sans-serif", background: C.bg, color: C.text, overflow: "hidden" }}>
      <Sidebar />
      <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
        <Header title="📊 Dashboard" subtitle={`Welcome back, ${userName}!`} />
        <div style={{ flex: 1, overflow: "auto", padding: "28px" }}>

          {/* Stats Row */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "16px", marginBottom: "28px" }}>
            <StatCard label="AI Queries" value={messages.filter(m => m.role === "user").length} color={C.accent} emoji="💬" bg={C.surface} />
            <StatCard label="Favourites" value={favourites.length} color={C.pink} emoji="❤️" bg={C.surface} />
            <StatCard label="Water Intake" value={`${waterCount}/8`} color={C.teal} emoji="💧" bg={C.surface} />
            <StatCard label="Meals Logged" value={calorieLog.length} color={C.green} emoji="🔥" bg={C.surface} />
          </div>

          {/* Main Grid */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "20px" }}>

            {/* BMI */}
            <div style={{ background: C.surface, borderRadius: "20px", padding: "28px", border: `1px solid ${C.border}` }}>
              <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "20px" }}>
                <div style={{ width: "40px", height: "40px", background: `${C.accent}20`, borderRadius: "10px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "20px" }}>⚖️</div>
                <div>
                  <h3 style={{ margin: 0, fontSize: "15px", fontWeight: "600" }}>BMI Calculator</h3>
                  <p style={{ margin: 0, fontSize: "11px", color: C.subtext }}>Body Mass Index</p>
                </div>
              </div>
              <div style={{ display: "flex", gap: "10px", marginBottom: "12px" }}>
                <input placeholder="Height (cm)" value={height} onChange={e => setHeight(e.target.value)}
                  style={{ flex: 1, padding: "11px 14px", background: C.card, border: `1px solid ${C.border}`, borderRadius: "10px", color: C.text, fontSize: "13px", outline: "none" }} />
                <input placeholder="Weight (kg)" value={weight} onChange={e => setWeight(e.target.value)}
                  style={{ flex: 1, padding: "11px 14px", background: C.card, border: `1px solid ${C.border}`, borderRadius: "10px", color: C.text, fontSize: "13px", outline: "none" }} />
              </div>
              <button onClick={() => { const h = height / 100; setBmi((weight / (h * h)).toFixed(1)); }}
                style={{ width: "100%", padding: "11px", background: `linear-gradient(135deg, ${C.accent}, #ff8c42)`, color: "white", border: "none", borderRadius: "10px", cursor: "pointer", fontWeight: "600", fontSize: "13px" }}>
                Calculate BMI
              </button>
              {bmi && (
                <div style={{ marginTop: "20px", display: "flex", alignItems: "center", gap: "16px", background: C.card, padding: "16px", borderRadius: "14px" }}>
                  <div style={{ fontSize: "42px", fontWeight: "800", color: bmi < 18.5 ? C.teal : bmi < 25 ? C.green : bmi < 30 ? C.yellow : "#ff3b30" }}>
                    {bmi}
                  </div>
                  <div>
                    <p style={{ margin: "0 0 3px", fontSize: "13px", fontWeight: "600" }}>
                      {bmi < 18.5 ? "Underweight" : bmi < 25 ? "Normal Weight ✅" : bmi < 30 ? "Overweight ⚠️" : "Obese ❗"}
                    </p>
                    <p style={{ margin: 0, fontSize: "11px", color: C.subtext }}>kg/m² · Based on WHO standards</p>
                  </div>
                </div>
              )}
            </div>

            {/* Water */}
            <div style={{ background: C.surface, borderRadius: "20px", padding: "28px", border: `1px solid ${C.border}` }}>
              <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "20px" }}>
                <div style={{ width: "40px", height: "40px", background: `${C.teal}20`, borderRadius: "10px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "20px" }}>💧</div>
                <div>
                  <h3 style={{ margin: 0, fontSize: "15px", fontWeight: "600" }}>Water Tracker</h3>
                  <p style={{ margin: 0, fontSize: "11px", color: C.subtext }}>Daily goal: 8 glasses</p>
                </div>
              </div>

              {/* Progress bar */}
              <div style={{ background: C.card, borderRadius: "10px", height: "8px", marginBottom: "16px", overflow: "hidden" }}>
                <div style={{ height: "100%", width: `${(waterCount / 8) * 100}%`, background: `linear-gradient(90deg, ${C.blue}, ${C.teal})`, borderRadius: "10px", transition: "width 0.4s ease" }} />
              </div>

              <div style={{ display: "flex", gap: "8px", marginBottom: "16px", flexWrap: "wrap" }}>
                {[...Array(8)].map((_, i) => (
                  <button key={i} onClick={() => setWaterCount(i + 1)} style={{
                    width: "44px", height: "44px", fontSize: "20px", background: i < waterCount ? `${C.teal}20` : C.card,
                    border: `1.5px solid ${i < waterCount ? C.teal : C.border}`,
                    borderRadius: "10px", cursor: "pointer", transition: "all 0.2s",
                    opacity: i < waterCount ? 1 : 0.4
                  }}>💧</button>
                ))}
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <p style={{ margin: 0, fontSize: "13px", color: waterCount >= 8 ? C.green : C.teal, fontWeight: "600" }}>
                  {waterCount >= 8 ? "🎉 Daily goal achieved!" : `${waterCount}/8 glasses · ${8 - waterCount} more to go`}
                </p>
                <button onClick={() => setWaterCount(0)} style={{ padding: "5px 12px", background: "transparent", border: `1px solid ${C.border}`, borderRadius: "8px", cursor: "pointer", color: C.subtext, fontSize: "11px" }}>Reset</button>
              </div>
            </div>

            {/* Calorie Log */}
            <div style={{ background: C.surface, borderRadius: "20px", padding: "28px", border: `1px solid ${C.border}` }}>
              <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "20px" }}>
                <div style={{ width: "40px", height: "40px", background: `${C.yellow}20`, borderRadius: "10px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "20px" }}>🔥</div>
                <div>
                  <h3 style={{ margin: 0, fontSize: "15px", fontWeight: "600" }}>Calorie Log</h3>
                  <p style={{ margin: 0, fontSize: "11px", color: C.subtext }}>Track your daily intake</p>
                </div>
              </div>
              <div style={{ display: "flex", gap: "8px", marginBottom: "14px" }}>
                <input placeholder="e.g. Idli 2 pcs — 150 kcal" value={calorieInput}
                  onChange={e => setCalorieInput(e.target.value)}
                  onKeyDown={e => { if (e.key === "Enter" && calorieInput) { setCalorieLog(p => [...p, calorieInput]); setCalorieInput(""); } }}
                  style={{ flex: 1, padding: "11px 14px", background: C.card, border: `1px solid ${C.border}`, borderRadius: "10px", color: C.text, fontSize: "13px", outline: "none" }} />
                <button onClick={() => { if (calorieInput) { setCalorieLog(p => [...p, calorieInput]); setCalorieInput(""); } }}
                  style={{ padding: "11px 16px", background: `linear-gradient(135deg, ${C.accent}, #ff8c42)`, color: "white", border: "none", borderRadius: "10px", cursor: "pointer", fontWeight: "600", fontSize: "13px" }}>
                  Add
                </button>
              </div>
              <div style={{ maxHeight: "180px", overflowY: "auto", display: "flex", flexDirection: "column", gap: "6px" }}>
                {calorieLog.length === 0 ? (
                  <p style={{ textAlign: "center", color: C.subtext, fontSize: "13px", padding: "24px 0" }}>No meals logged yet</p>
                ) : calorieLog.map((log, i) => (
                  <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", background: C.card, padding: "9px 13px", borderRadius: "9px", fontSize: "12px" }}>
                    <span>🍽️ {log}</span>
                    <button onClick={() => setCalorieLog(p => p.filter((_, idx) => idx !== i))} style={{ background: "none", border: "none", color: "#ff3b30", cursor: "pointer", fontSize: "16px", lineHeight: 1 }}>×</button>
                  </div>
                ))}
              </div>
            </div>

            {/* Quick Info */}
            <div style={{ background: C.surface, borderRadius: "20px", padding: "28px", border: `1px solid ${C.border}` }}>
              <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "20px" }}>
                <div style={{ width: "40px", height: "40px", background: `${C.green}20`, borderRadius: "10px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "20px" }}>📈</div>
                <div>
                  <h3 style={{ margin: 0, fontSize: "15px", fontWeight: "600" }}>Health Tips</h3>
                  <p style={{ margin: 0, fontSize: "11px", color: C.subtext }}>Based on your profile</p>
                </div>
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
                {[
                  { tip: "Drink water before every meal", icon: "💧" },
                  { tip: `${mealTime.label} time — eat mindfully`, icon: mealTime.emoji },
                  { tip: mood ? `Feeling ${mood}? Food can help!` : "Set your mood for better suggestions", icon: "😊" },
                  { tip: bmi ? (bmi < 25 ? "Great BMI! Keep it up 💪" : "Consider lighter meal options") : "Calculate your BMI above", icon: "⚖️" },
                  { tip: waterCount >= 8 ? "Water goal achieved! Amazing!" : `${8 - waterCount} more glasses of water to go`, icon: "🎯" },
                ].map((item, i) => (
                  <div key={i} style={{ display: "flex", alignItems: "center", gap: "10px", background: C.card, padding: "11px 14px", borderRadius: "10px" }}>
                    <span style={{ fontSize: "18px" }}>{item.icon}</span>
                    <p style={{ margin: 0, fontSize: "12px", color: C.text }}>{item.tip}</p>
                  </div>
                ))}
              </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );

  // MEAL PLANNER
  if (page === "mealplan") return (
    <div style={{ display: "flex", height: "100vh", fontFamily: "'Segoe UI', sans-serif", background: C.bg, color: C.text, overflow: "hidden" }}>
      <Sidebar />
      <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
        <Header title="🗓️ Meal Planner" subtitle="AI-powered daily meal planning" />
        <div style={{ flex: 1, overflow: "auto", padding: "28px" }}>
          <div style={{ maxWidth: "720px", margin: "0 auto" }}>

            {/* Preferences */}
            <div style={{ background: C.surface, borderRadius: "20px", padding: "28px", border: `1px solid ${C.border}`, marginBottom: "20px" }}>
              <h3 style={{ margin: "0 0 20px", fontSize: "15px" }}>Your Preferences</h3>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "12px", marginBottom: "24px" }}>
                {[
                  { label: "Diet", value: dietType !== "Any" ? dietType : "No restriction", emoji: "🥗" },
                  { label: "Cuisine", value: cuisine, emoji: "🍽️" },
                  { label: "Mood", value: mood || "Not set", emoji: "😊" },
                  { label: "BMI", value: bmi ? `${bmi}` : "Not set", emoji: "⚖️" },
                ].map((p, i) => (
                  <div key={i} style={{ background: C.card, padding: "14px", borderRadius: "12px", textAlign: "center", border: `1px solid ${C.border}` }}>
                    <p style={{ margin: "0 0 6px", fontSize: "20px" }}>{p.emoji}</p>
                    <p style={{ margin: "0 0 3px", fontSize: "10px", color: C.subtext, textTransform: "uppercase", letterSpacing: "0.5px" }}>{p.label}</p>
                    <p style={{ margin: 0, fontSize: "12px", fontWeight: "600" }}>{p.value}</p>
                  </div>
                ))}
              </div>
              <button onClick={generateMealPlan} disabled={mealPlanLoading}
                style={{
                  width: "100%", padding: "14px", background: mealPlanLoading ? C.card : `linear-gradient(135deg, ${C.accent}, #ff8c42)`,
                  color: mealPlanLoading ? C.subtext : "white", border: "none", borderRadius: "12px",
                  cursor: mealPlanLoading ? "not-allowed" : "pointer", fontWeight: "700", fontSize: "14px",
                  boxShadow: mealPlanLoading ? "none" : `0 6px 20px ${C.accent}40`
                }}>
                {mealPlanLoading ? "⏳ Generating your personalized meal plan..." : "✨ Generate AI Meal Plan"}
              </button>
            </div>

            {/* Meal Plan Result */}
            {mealPlan && (
              <div style={{ background: C.surface, borderRadius: "20px", padding: "28px", border: `1px solid ${C.border}` }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "20px" }}>
                  <h3 style={{ margin: 0, color: C.accent, fontSize: "15px" }}>📋 Your Personalized Meal Plan</h3>
                  <button onClick={() => { navigator.clipboard.writeText(mealPlan); alert("Copied!"); }}
                    style={{ padding: "7px 14px", background: C.card, border: `1px solid ${C.border}`, borderRadius: "8px", cursor: "pointer", color: C.text, fontSize: "12px" }}>
                    📋 Copy
                  </button>
                </div>
                <div style={{ whiteSpace: "pre-wrap", lineHeight: "2", fontSize: "14px", color: C.text }}>
                  {mealPlan}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );

  // MAIN CHAT
  return (
    <div style={{ display: "flex", height: "100vh", fontFamily: "'Segoe UI', sans-serif", background: C.bg, color: C.text, overflow: "hidden" }}>
      <Sidebar />
      <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
        <Header
          title="🤖 NutriAI Chef"
          subtitle={`${cuisine} cuisine · ${mealTime.label}${mood ? ` · ${mood}` : ""}${dietType !== "Any" ? ` · ${dietType}` : ""}`}
        />

        {/* Messages */}
        <div style={{ flex: 1, overflow: "auto", padding: "24px 28px" }}>
          {messages.length <= 1 && (
            <div style={{ marginBottom: "28px" }}>
              <p style={{ color: C.subtext, fontSize: "12px", marginBottom: "12px", textTransform: "uppercase", letterSpacing: "1px", fontWeight: "600" }}>Quick Prompts</p>
              <div style={{ display: "flex", flexWrap: "wrap", gap: "8px" }}>
                {QUICK_PROMPTS.map((p, i) => (
                  <button key={i} onClick={() => getSuggestion(p.text)} style={{
                    padding: "9px 16px", background: C.surface, color: C.text,
                    border: `1px solid ${C.border}`, borderRadius: "20px", cursor: "pointer",
                    fontSize: "13px", transition: "all 0.2s",
                    display: "flex", alignItems: "center", gap: "6px"
                  }}
                    onMouseEnter={e => e.currentTarget.style.borderColor = C.accent}
                    onMouseLeave={e => e.currentTarget.style.borderColor = C.border}
                  >
                    <span>{p.emoji}</span> {p.text}
                  </button>
                ))}
              </div>
            </div>
          )}

          {messages.map((msg, i) => (
            <div key={i} style={{ display: "flex", justifyContent: msg.role === "user" ? "flex-end" : "flex-start", marginBottom: "20px", gap: "10px" }}>
              {msg.role === "ai" && (
                <div style={{ width: "36px", height: "36px", background: `linear-gradient(135deg, ${C.accent}, #ff8c42)`, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "18px", flexShrink: 0, alignSelf: "flex-end" }}>🤖</div>
              )}
              <div style={{ maxWidth: "66%" }}>
                <div style={{
                  background: msg.role === "user" ? `linear-gradient(135deg, ${C.blue}, ${C.purple})` : C.surface,
                  color: msg.role === "user" ? "white" : C.text,
                  padding: "14px 18px",
                  borderRadius: msg.role === "user" ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
                  fontSize: "14px", lineHeight: "1.7",
                  whiteSpace: "pre-wrap",
                  border: msg.role === "ai" ? `1px solid ${C.border}` : "none",
                  boxShadow: "0 2px 12px rgba(0,0,0,0.15)"
                }}>
                  {msg.text === "typing" ? (
                    <span style={{ color: C.subtext, letterSpacing: "3px" }}>● ● ●</span>
                  ) : msg.text}
                </div>
                {msg.role === "ai" && msg.text !== "typing" && (
                  <div style={{ display: "flex", gap: "6px", marginTop: "8px" }}>
                    <button onClick={() => { setFavourites(p => p.includes(msg.text) ? p.filter(f => f !== msg.text) : [...p, msg.text]); }}
                      style={{ padding: "4px 12px", fontSize: "11px", background: "transparent", border: `1px solid ${C.border}`, borderRadius: "10px", cursor: "pointer", color: favourites.includes(msg.text) ? C.pink : C.subtext, transition: "all 0.2s" }}>
                      {favourites.includes(msg.text) ? "❤️ Saved" : "🤍 Save"}
                    </button>
                    <button onClick={() => { navigator.clipboard.writeText(msg.text); }}
                      style={{ padding: "4px 12px", fontSize: "11px", background: "transparent", border: `1px solid ${C.border}`, borderRadius: "10px", cursor: "pointer", color: C.subtext }}>
                      📋 Copy
                    </button>
                  </div>
                )}
                {msg.time && <p style={{ fontSize: "10px", color: C.subtext, margin: "5px 0 0", textAlign: msg.role === "user" ? "right" : "left" }}>{msg.time}</p>}
              </div>
              {msg.role === "user" && (
                <div style={{ width: "36px", height: "36px", background: `linear-gradient(135deg, ${C.blue}, ${C.purple})`, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "15px", fontWeight: "700", color: "white", flexShrink: 0, alignSelf: "flex-end" }}>
                  {userName.charAt(0).toUpperCase()}
                </div>
              )}
            </div>
          ))}
          <div ref={chatEndRef} />
        </div>

        {/* Input */}
        <div style={{ padding: "16px 24px", borderTop: `1px solid ${C.border}`, background: C.sidebar }}>
          {(mood || dietType !== "Any" || cuisine !== "Any") && (
            <div style={{ display: "flex", gap: "6px", marginBottom: "10px", flexWrap: "wrap" }}>
              {mood && <span style={{ padding: "3px 10px", background: `${C.accent}20`, color: C.accent, borderRadius: "10px", fontSize: "11px", border: `1px solid ${C.accent}30` }}>{mood}</span>}
              {dietType !== "Any" && <span style={{ padding: "3px 10px", background: `${C.teal}20`, color: C.teal, borderRadius: "10px", fontSize: "11px", border: `1px solid ${C.teal}30` }}>{dietType}</span>}
              {cuisine !== "Any" && <span style={{ padding: "3px 10px", background: `${C.blue}20`, color: C.blue, borderRadius: "10px", fontSize: "11px", border: `1px solid ${C.blue}30` }}>{cuisine}</span>}
            </div>
          )}
          <div style={{ display: "flex", gap: "10px", alignItems: "center" }}>
            <input
              style={{
                flex: 1, padding: "14px 20px",
                background: C.card, border: `1.5px solid ${C.border}`,
                borderRadius: "25px", color: C.text, fontSize: "14px", outline: "none",
                transition: "border 0.2s"
              }}
              placeholder={`Ask NutriAI about ${mealTime.label.toLowerCase()} ideas...`}
              value={query}
              onChange={e => setQuery(e.target.value)}
              onKeyDown={e => e.key === "Enter" && getSuggestion()}
              onFocus={e => e.target.style.borderColor = C.accent}
              onBlur={e => e.target.style.borderColor = C.border}
            />
            <button
              onClick={() => getSuggestion()}
              disabled={loading}
              style={{
                width: "48px", height: "48px",
                background: loading ? C.card : `linear-gradient(135deg, ${C.accent}, #ff8c42)`,
                color: loading ? C.subtext : "white",
                border: "none", borderRadius: "50%", cursor: loading ? "not-allowed" : "pointer",
                fontSize: "18px", flexShrink: 0,
                boxShadow: loading ? "none" : `0 4px 15px ${C.accent}40`,
                transition: "all 0.2s"
              }}>
              {loading ? "⏳" : "🚀"}
            </button>
          </div>
          <p style={{ fontSize: "11px", color: C.subtext, textAlign: "center", margin: "10px 0 0" }}>
            Powered by Groq AI · Press Enter to send
          </p>
        </div>
      </div>
    </div>
  );
}
